SELECT * FROM sys_log WHERE 1=1

    AND (username LIKE CONCAT('%', #{query.keyword}, '%')
         OR operation LIKE CONCAT('%', #{query.keyword}, '%'))

AND username = #{query.username}
AND operation LIKE CONCAT('%', #{query.operation}, '%')
AND create_time >= #{query.dateStart}
AND create_time <= #{query.dateEnd}
ORDER BY create_time DESC
